def generate_saml_response(username, user_attributes, request_id, acs_url, sp_entity_id):
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_before = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_on_or_after = (datetime.utcnow() + timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    
    assertion_id = '_' + str(uuid.uuid4())
    response_id = '_' + str(uuid.uuid4())
    
    # Build attribute statements
    attributes_xml = ''
    for attr_name, attr_value in user_attributes.items():
        attributes_xml += f'''
        <saml:Attribute Name="{attr_name}" NameFormat="urn:oasis:names:tc:SAML:2.0:attrname-format:basic">
            <saml:AttributeValue xmlns:xs="http://www.w3.org/2001/XMLSchema" 
                                  xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" 
                                  xsi:type="xs:string">{attr_value}</saml:AttributeValue>
        </saml:Attribute>'''
    
    # Create SAML Assertion
    assertion_xml = f'''<saml:Assertion xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" 
                         ID="{assertion_id}" 
                         IssueInstant="{issue_instant}" 
                         Version="2.0">
    <saml:Issuer>https://idp.example.com</saml:Issuer>
    <saml:Subject>
        <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{username}</saml:NameID>
        <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
            <saml:SubjectConfirmationData InResponseTo="{request_id}" 
                                           NotOnOrAfter="{not_on_or_after}" 
                                           Recipient="{acs_url}"/>
        </saml:SubjectConfirmation>
    </saml:Subject>
    <saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
        <saml:AudienceRestriction>
            <saml:Audience>{sp_entity_id}</saml:Audience>
        </saml:AudienceRestriction>
    </saml:Conditions>
    <saml:AuthnStatement AuthnInstant="{issue_instant}" SessionIndex="{assertion_id}">
        <saml:AuthnContext>
            <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
        </saml:AuthnContext>
    </saml:AuthnStatement>
    <saml:AttributeStatement>{attributes_xml}
    </saml:AttributeStatement>
</saml:Assertion>'''
    
    # Sign the assertion
    assertion_element = etree.fromstring(assertion_xml.encode('utf-8'))
    signer = XMLSigner(
        method=signxml.methods.enveloped,
        signature_algorithm="rsa-sha256",
        digest_algorithm="sha256"
    )
    
    signed_assertion = signer.sign(
        assertion_element,
        key=KEY_PEM,
        cert=CERT_PEM
    )
    
    signed_assertion_str = etree.tostring(signed_assertion, encoding='unicode')
    
    # Create SAML Response
    response_xml = f'''<samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" 
                        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                        ID="{response_id}" 
                        Version="2.0" 
                        IssueInstant="{issue_instant}"
                        Destination="{acs_url}"
                        InResponseTo="{request_id}">
    <saml:Issuer>https://idp.example.com</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
    </samlp:Status>
    {signed_assertion_str}
</samlp:Response>'''
    
    return response_xml

