@app.route('/sso', methods=['GET', 'POST'])
def sso():
    saml_request = request.args.get('SAMLRequest') or request.form.get('SAMLRequest')
    relay_state = request.args.get('RelayState') or request.form.get('RelayState') or ''
    
    if not saml_request:
        return 'Missing SAMLRequest parameter', 400
    
    # Decode and inflate SAML request
    try:
        decoded = base64.b64decode(saml_request)
        import zlib
        try:
            inflated = zlib.decompress(decoded, -15)
        except:
            inflated = decoded
        
        saml_request_xml = inflated.decode('utf-8')
        
        # Parse SAML request
        root = etree.fromstring(saml_request_xml.encode('utf-8'))
        
        # Extract request ID
        request_id = root.get('ID')
        acs_url = root.get('AssertionConsumerServiceURL')
        
        # Extract issuer (SP entity ID)
        issuer_elem = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Issuer')
        sp_entity_id = issuer_elem.text if issuer_elem is not None else None
        
    except Exception as e:
        return f'Invalid SAMLRequest: {str(e)}', 400
    
    # Show login form
    return render_template_string(LOGIN_TEMPLATE, 
                                   saml_request=saml_request, 
                                   relay_state=relay_state,
                                   error=None)

@app.route('/sso/login', methods=['POST'])
def login():
    username = request.form.get('username')
    password = request.form.get('password')
    saml_request = request.form.get('SAMLRequest')
    relay_state = request.form.get('RelayState', '')
    
    # Authenticate user
    if username not in USERS or USERS[username]['password'] != password:
        return render_template_string(LOGIN_TEMPLATE, 
                                       saml_request=saml_request, 
                                       relay_state=relay_state,
                                       error='Invalid username or password')
    
    # Decode SAML request to get parameters
    try:
        decoded = base64.b64decode(saml_request)
        import zlib
        try:
            inflated = zlib.decompress(decoded, -15)
        except:
            inflated = decoded
        
        saml_request_xml = inflated.decode('utf-8')
        root = etree.fromstring(saml_request_xml.encode('utf-8'))
        
        request_id = root.get('ID')
        acs_url = root.get('AssertionConsumerServiceURL')
        
        issuer_elem = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Issuer')
        sp_entity_id = issuer_elem.text if issuer_elem is not None else None
        
    except Exception as e:
        return f'Invalid SAMLRequest: {str(e)}', 400
    
    # Generate SAML response
    user_attributes = USERS[username]['attributes']
    saml_response_xml = generate_saml_response(
        username, 
        user_attributes, 
        request_id, 
        acs_url, 
        sp_entity_id
    )
    
    # Encode SAML response
    saml_response_encoded = base64.b64encode(saml_response_xml.encode('utf-8')).decode('utf-8')
    
    # Return auto-submit form
    return render_template_string(SAML_POST_FORM, 
                                   acs_url=acs_url, 
                                   saml_response=saml_response_encoded,
                                   relay_state=relay_state)

